import java.io.IOException;
import java.io.PrintWriter;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class SecureServlet extends HttpServlet {

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");
        PrintWriter out = response.getWriter();

        if (userInput != null) {
            // Sanitize and escape user input before displaying
            String sanitizedInput = sanitizeUserInput(userInput);
            out.println("<h1>Welcome " + sanitizedInput + "</h1>");
        } else {
            out.println("<h1>Welcome Guest</h1>");
        }
    }

    private String sanitizeUserInput(String input) {
        // Implement proper sanitization logic here (e.g., using OWASP Java Encoder)
        return org.owasp.encoder.Encode.forHtml(input);
    }
}

